import { type PropsWithChildren } from 'react';

import { ConnectionLayerTooltip } from './ConnectionLayerTooltip.js';
import type {
  Connection,
  ConnectionLayerProps,
} from '../types/connection-layer.js';

/**
 * The `ConnectionLayer` component renders connections between points on a map,
 * accepting an array of `Connection` data points with required properties like
 * latitude and longitude. It supports customization of color, thickness,
 * direction the connection indicators.
 * @public
 */
export const ConnectionLayer = <T extends Connection>(
  _: PropsWithChildren<ConnectionLayerProps<T>>,
) => null;

ConnectionLayer.Tooltip = ConnectionLayerTooltip;

ConnectionLayer['displayName'] = 'ConnectionLayerSlot';
